1	------------------------------------------------------------------------------
2	--  Copyright (c) 2019 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This entity implements a simple AXI master. Simple means: It does not
11	-- support any unaligned reads/writes and it does not do any width conversions.
12	-- It just executes the transfers requested and splits them into multiple AXI
13	-- transactions in order to not burst over 4k boundaries and respect the maximum
14	-- transaction size.
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.numeric_std.all;
19	
20	use work.psi_common_math_pkg.all;
21	use work.psi_common_logic_pkg.all;
22	--@fomratter:off
23	entity psi_common_axi_master_simple is
24	  generic(
25	    axi_addr_width_g             : natural range 12 to 64  := 32;   -- $$ constant=32 $$
26	    axi_data_width_g             : natural range 8 to 1024 := 32;   -- $$ constant=16 $$
27	    axi_max_beats_g              : natural range 1 to 256  := 256;  -- $$ constant=16 $$
28	    axi_max_open_transactions_g  : natural range 1 to 8    := 8;    -- $$ constant=3 $$
29	    user_transaction_size_bits_g : natural                 := 32;   -- $$ constant=10 $$
30	    data_fifo_depth_g            : natural                 := 1024; -- $$ constant=10 $$
31	    impl_read_g                  : boolean                 := true; -- $$ export=true $$
32	    impl_write_g                 : boolean                 := true; -- $$ export=true $$
33	    ram_behavior_g               : string                  := "RBW" -- $$ constant="RBW" $$
34	  );
35	  port(
36	    -- Control Signals
37	    m_axi_aclk       : in  std_logic;                                                                       -- $$ type=clk; freq=100e6 $$
38	    m_axi_aresetn    : in  std_logic;                                                                       -- $$ type=rst; clk=M_Axi_Aclk; lowactive=true $$
39	    -- User Command Interface
40	    cmd_wr_addr_i    : in  std_logic_vector(axi_addr_width_g - 1 downto 0)             := (others => '0');  -- $$ proc=user_cmd $$
41	    cmd_wr_size_i    : in  std_logic_vector(user_transaction_size_bits_g - 1 downto 0) := (others => '0');  -- $$ proc=user_cmd $$
42	    cmd_wr_low_lat_i : in  std_logic                                                   := '0';              -- $$ proc=user_cmd $$
43	    cmd_wr_vld_i     : in  std_logic                                                   := '0';              -- $$ proc=user_cmd $$
44	    cmd_wr_rdy_o     : out std_logic;                                                                       -- $$ proc=user_cmd $$
45	    -- User Command Interface
46	    cmd_rd_addr_i    : in  std_logic_vector(axi_addr_width_g - 1 downto 0)             := (others => '0');  -- $$ proc=user_cmd $$
47	    cmd_rd_size_o    : in  std_logic_vector(user_transaction_size_bits_g - 1 downto 0) := (others => '0');  -- $$ proc=user_cmd $$
48	    cmd_rd_low_lat_i : in  std_logic                                                   := '0';              -- $$ proc=user_cmd $$
49	    cmd_rd_vld_i     : in  std_logic                                                   := '0';              -- $$ proc=user_cmd $$
50	    cmd_rd_rdy_o     : out std_logic;                                                                       -- $$ proc=user_cmd $$
51	    -- Write Data
52	    wr_dat_i         : in  std_logic_vector(axi_data_width_g - 1 downto 0)             := (others => '0');  -- $$ proc=user_data $$
53	    wr_data_be_i     : in  std_logic_vector(axi_data_width_g / 8 - 1 downto 0)         := (others => '0');  -- $$ proc=user_data $$
54	    wr_vld_i         : in  std_logic                                                   := '0';              -- $$ proc=user_data $$
55	    wr_rdy_o         : out std_logic;                                                                       -- $$ proc=user_data $$
56	    -- Read Data
57	    rd_dat_o         : out std_logic_vector(axi_data_width_g - 1 downto 0);                                 -- $$ proc=user_data $$
58	    rd_vld_o         : out std_logic;                                                                       -- $$ proc=user_data $$
59	    rd_rdy_i         : in  std_logic                                                   := '0';              -- $$ proc=user_data $$
60	    -- Response
61	    wr_done_o        : out std_logic;                                                                       -- $$ proc=user_resp $$
62	    wr_error_o       : out std_logic;                                                                       -- $$ proc=user_resp $$
63	    rd_done_o        : out std_logic;                                                                       -- $$ proc=user_resp $$
64	    rd_error_o       : out std_logic;                                                                       -- $$ proc=user_resp $$
65	    -- AXI Address Write Channel
66	    m_axi_awaddr     : out std_logic_vector(axi_addr_width_g - 1 downto 0);                                 -- $$ proc=axi $$
67	    m_axi_awlen      : out std_logic_vector(7 downto 0);                                                    -- $$ proc=axi $$
68	    m_axi_awsize     : out std_logic_vector(2 downto 0);                                                    -- $$ proc=axi $$
69	    m_axi_awburst    : out std_logic_vector(1 downto 0);                                                    -- $$ proc=axi $$
70	    m_axi_awlock     : out std_logic;                                                                       -- $$ proc=axi $$
71	    m_axi_awcache    : out std_logic_vector(3 downto 0);                                                    -- $$ proc=axi $$
72	    m_axi_awprot     : out std_logic_vector(2 downto 0);                                                    -- $$ proc=axi $$
73	    m_axi_awvalid    : out std_logic;                                                                       -- $$ proc=axi $$
74	    m_axi_awready    : in  std_logic                                                   := '0';              -- $$ proc=axi $$
75	    -- AXI Write Data Channel                                                                               -- $$ proc=axi $$
76	    m_axi_wdata      : out std_logic_vector(axi_data_width_g - 1 downto 0);                                 -- $$ proc=axi $$
77	    m_axi_wstrb      : out std_logic_vector(axi_data_width_g / 8 - 1 downto 0);                             -- $$ proc=axi $$
78	    m_axi_wlast      : out std_logic;                                                                       -- $$ proc=axi $$
79	    m_axi_wvalid     : out std_logic;                                                                       -- $$ proc=axi $$
80	    m_axi_wready     : in  std_logic                                                   := '0';              -- $$ proc=axi $$
81	    -- AXI Write Response Channel
82	    m_axi_bresp      : in  std_logic_vector(1 downto 0)                                := (others => '0');  -- $$ proc=axi $$
83	    m_axi_bvalid     : in  std_logic                                                   := '0';              -- $$ proc=axi $$
84	    m_axi_bready     : out std_logic;                                                                       -- $$ proc=axi $$
85	    -- AXI Read Address Channel
86	    m_axi_araddr     : out std_logic_vector(axi_addr_width_g - 1 downto 0);                                 -- $$ proc=axi $$
87	    m_axi_arlen      : out std_logic_vector(7 downto 0);                                                    -- $$ proc=axi $$
88	    m_axi_arsize     : out std_logic_vector(2 downto 0);                                                    -- $$ proc=axi $$
89	    m_axi_arburst    : out std_logic_vector(1 downto 0);                                                    -- $$ proc=axi $$
90	    m_axi_arlock     : out std_logic;                                                                       -- $$ proc=axi $$
91	    m_axi_arcache    : out std_logic_vector(3 downto 0);                                                    -- $$ proc=axi $$
92	    m_axi_arprot     : out std_logic_vector(2 downto 0);                                                    -- $$ proc=axi $$
93	    m_axi_arvalid    : out std_logic;                                                                       -- $$ proc=axi $$
94	    m_axi_arready    : in  std_logic                                                   := '0';              -- $$ proc=axi $$
95	    -- AXI Read Data Channel
96	    m_axi_rdata      : in  std_logic_vector(axi_data_width_g - 1 downto 0)             := (others => '0');  -- $$ proc=axi $$
97	    m_axi_rresp      : in  std_logic_vector(1 downto 0)                                := (others => '0');  -- $$ proc=axi $$
98	    m_axi_rlast      : in  std_logic                                                   := '0';              -- $$ proc=axi $$
99	    m_axi_rvalid     : in  std_logic                                                   := '0';              -- $$ proc=axi $$
100	    m_axi_rready     : out std_logic                                                                        -- $$ proc=axi $$
101	  );
102	end entity;
103	--@fomratter:on
104	
105	architecture rtl of psi_common_axi_master_simple is
106	
107	  ------------------------------------------------------------------------------
108	  -- Constants
109	  ------------------------------------------------------------------------------
110	  constant Axi_BurstType_Incr_c : std_logic_vector(1 downto 0) := "01";
111	  constant Axi_Resp_Okay_c      : std_logic_vector(1 downto 0) := "00";
112	  constant UnusedAddrBits_c     : natural                      := log2(axi_data_width_g / 8);
113	
114	  constant BeatsBits_c       : natural := log2ceil(axi_max_beats_g + 1);
115	  subtype Trans_AddrRange_c is natural range cmd_wr_addr_i'high downto 0;
116	  subtype Trans_BurstRange_c is natural range BeatsBits_c + Trans_AddrRange_c'high downto Trans_AddrRange_c'high + 1;
117	  constant Trans_LowLatIdx_c : natural := Trans_BurstRange_c'high + 1;
118	  constant Trans_Size_c      : natural := Trans_LowLatIdx_c + 1;
119	  constant MaxBeatsNoCmd_c   : natural := max(axi_max_beats_g * axi_max_open_transactions_g, data_fifo_depth_g);
120	
121	  ------------------------------------------------------------------------------
122	  -- Type
123	  ------------------------------------------------------------------------------
124	  type WriteTfGen_s is (Idle_s, MaxCalc_s, GenTf_s, WriteTf_s);
125	  type ReadTfGen_s is (Idle_s, MaxCalc_s, GenTf_s, WriteTf_s);
126	  type AwFsm_s is (Idle_s, Wait_s);
127	  type ArFsm_s is (Idle_s, Wait_s);
128	  type WFsm_s is (Idle_s, NonLast_s, Last_s);
129	
130	  ------------------------------------------------------------------------------
131	  -- Functions
132	  ------------------------------------------------------------------------------
133	  function AddrMasked_f(Addr : in std_logic_vector) return std_logic_vector is
134	    variable Masked_v : std_logic_vector(Addr'range);
135	  begin
136	    Masked_v                                := Addr;
137	    Masked_v(UnusedAddrBits_c - 1 downto 0) := (others => '0');
138	    return Masked_v;
139	  end function;
140	
141	  ------------------------------------------------------------------------------
142	  -- Two Process Record
143	  ------------------------------------------------------------------------------
144	  type two_process_r is record
145	
146	    -- *** Write Related Registers ***
147	    -- Command Interface
148	    cmd_wr_rdy_o    : std_logic;
149	    wr_error_o      : std_logic;
150	    wr_done_o       : std_logic;
151	    -- Generate Write Transactions
152	    WriteTfGenState : WriteTfGen_s;
153	    WrAddr          : unsigned(cmd_wr_addr_i'range);
154	    WrBeats         : unsigned(cmd_wr_size_i'range);
155	    WrLowLat        : std_logic;
156	    WrMaxBeats      : unsigned(BeatsBits_c - 1 downto 0);
157	    WrTfBeats       : unsigned(BeatsBits_c - 1 downto 0);
158	    WrTfVld         : std_logic;
159	    WrTfIsLast      : std_logic;
160	    -- Execute Aw Commands
161	    AwFsm           : AwFsm_s;
162	    AwFsmRdy        : std_logic;
163	    AwCmdSent       : std_logic;
164	    AwCmdSize       : unsigned(BeatsBits_c - 1 downto 0);
165	    AwCmdSizeMin1   : unsigned(BeatsBits_c - 1 downto 0); -- 	AwCmdSize-1 for timing optimization reasons
166	    WDataFifoWrite  : std_logic;
167	    -- Execute W Data
168	    WFsm            : WFsm_s;
169	    WDataFifoRd     : std_logic;
170	    WDataEna        : std_logic;
171	    WDataBeats      : unsigned(BeatsBits_c - 1 downto 0);
172	    -- Write Response
173	    WrRespError     : std_logic;
174	    -- Write General
175	    WrOpenTrans     : integer range -1 to axi_max_open_transactions_g;
176	    WrBeatsNoCmd    : signed(log2ceil(MaxBeatsNoCmd_c + 1) downto 0);
177	    -- AXI Signals
178	    m_axi_awaddr    : std_logic_vector(m_axi_awaddr'range);
179	    m_axi_awlen     : std_logic_vector(m_axi_awlen'range);
180	    m_axi_awvalid   : std_logic;
181	    m_axi_wlast     : std_logic;
182	
183	    -- *** Read Related Registers ***
184	    -- Command Interface
185	    cmd_rd_rdy_o    : std_logic;
186	    rd_error_o      : std_logic;
187	    rd_done_o       : std_logic;
188	    -- Generate Read Transactions
189	    ReadTfGenState  : ReadTfGen_s;
190	    RdAddr          : unsigned(cmd_rd_addr_i'range);
191	    RdBeats         : unsigned(cmd_rd_size_o'range);
192	    RdLowLat        : std_logic;
193	    RdMaxBeats      : unsigned(BeatsBits_c - 1 downto 0);
194	    RdTfBeats       : unsigned(BeatsBits_c - 1 downto 0);
195	    RdTfVld         : std_logic;
196	    RdTfIsLast      : std_logic;
197	    -- Execute Ar Commands
198	    ArFsm           : ArFsm_s;
199	    ArFsmRdy        : std_logic;
200	    ArCmdSent       : std_logic;
201	    ArCmdSize       : unsigned(BeatsBits_c - 1 downto 0);
202	    ArCmdSizeMin1   : unsigned(BeatsBits_c - 1 downto 0); -- 	ArCmdSize-1 for timing optimization reasons
203	    RDataFifoRead   : std_logic;
204	    -- Write Response
205	    RdRespError     : std_logic;
206	    -- Read General
207	    RdOpenTrans     : unsigned(log2ceil(axi_max_open_transactions_g + 1) - 1 downto 0);
208	    RdFifoSpaceFree : signed(log2ceil(MaxBeatsNoCmd_c + 1) downto 0);
209	    -- AXI Signals
210	    m_axi_araddr    : std_logic_vector(m_axi_araddr'range);
211	    m_axi_arlen     : std_logic_vector(m_axi_arlen'range);
212	    m_axi_arvalid   : std_logic;
213	
214	  end record;
215	  signal r, r_next : two_process_r;
216	
217	  ------------------------------------------------------------------------------
218	  -- Instantiation Signals
219	  ------------------------------------------------------------------------------
220	 -- signal Rst               : std_logic;
221	  signal WrDataFifoORdy    : std_logic;
222	  signal WrDataFifoOVld    : std_logic;
223	  signal WrTransFifoInVld  : std_logic;
224	  signal WrTransFifoBeats  : std_logic_vector(BeatsBits_c - 1 downto 0);
225	  signal WrTransFifoOutVld : std_logic;
226	  signal WrRespIsLast      : std_logic;
227	  signal WrRespFifoVld     : std_logic;
228	  signal WrData_Rdy_I      : std_logic;
229	  signal RdTransFifoInVld  : std_logic;
230	  signal RdRespIsLast      : std_logic;
231	  signal RdRespFifoVld     : std_logic;
232	  signal RdDat_Vld_I       : std_logic;
233	  signal RdRespLast        : std_logic;
234	  signal M_Axi_RReady_I    : std_logic;
235	
236	begin
237	
238	  ------------------------------------------------------------------------------
239	  -- Assertions
240	  ------------------------------------------------------------------------------
241	  assert axi_data_width_g mod 8 = 0 report "###ERROR###: psi_common_axi_master_simple axi_data_width_g must be a multiple of 8" severity failure;
242	
243	  ------------------------------------------------------------------------------
244	  -- Combinatorial Process
245	  ------------------------------------------------------------------------------
246	  p_comb : process(r, m_axi_awready, m_axi_bvalid, m_axi_bresp, WrDataFifoORdy, WrDataFifoOVld, WrTransFifoOutVld, WrTransFifoBeats, WrRespIsLast, WrRespFifoVld, cmd_wr_addr_i, cmd_wr_size_i, cmd_wr_low_lat_i, cmd_wr_vld_i, wr_vld_i, WrData_Rdy_I, m_axi_arready, RdRespIsLast, RdRespFifoVld, RdRespLast, cmd_rd_addr_i, cmd_rd_size_o, cmd_rd_low_lat_i, cmd_rd_vld_i, rd_rdy_i, RdDat_Vld_I)
247	    variable v               : two_process_r;
248	    variable WrMax4kBeats_v  : unsigned(13 - UnusedAddrBits_c downto 0);
249	    variable RdMax4kBeats_v  : unsigned(13 - UnusedAddrBits_c downto 0);
250	    variable Stdlv9Bit_v     : std_logic_vector(8 downto 0);
251	    variable WDataTransfer_v : boolean;
252	    variable StartWBurst_v   : boolean := true;
253	  begin
254	    -- *** Keep two process variables stable ***
255	    v := r;
256	
257	    --------------------------------------------------------------------------
258	    -- Write Related Code
259	    --------------------------------------------------------------------------
260	    if impl_write_g then
261	
262	      -- *** Write Transfer Generation ***
263	      WrMax4kBeats_v := (others => '0');
264	      case r.WriteTfGenState is
265	        when Idle_s =>
266	          v.cmd_wr_rdy_o := '1';
267	          if (r.cmd_wr_rdy_o = '1') and (cmd_wr_vld_i = '1') then
268	            v.cmd_wr_rdy_o    := '0';
269	            v.WrAddr          := unsigned(AddrMasked_f(cmd_wr_addr_i));
270	            v.WrBeats         := unsigned(cmd_wr_size_i);
271	            v.WrLowLat        := cmd_wr_low_lat_i;
272	            v.WriteTfGenState := MaxCalc_s;
273	          end if;
274	
275	        when MaxCalc_s =>
276	          WrMax4kBeats_v    := resize(unsigned('0' & not r.WrAddr(11 downto UnusedAddrBits_c)) + 1, WrMax4kBeats_v'length);
277	          if WrMax4kBeats_v > axi_max_beats_g then
278	            v.WrMaxBeats := to_unsigned(axi_max_beats_g, BeatsBits_c);
279	          else
280	            v.WrMaxBeats := WrMax4kBeats_v(BeatsBits_c - 1 downto 0);
281	          end if;
282	          v.WriteTfGenState := GenTf_s;
283	
284	        when GenTf_s =>
285	          if (r.WrMaxBeats < r.WrBeats) then
286	            v.WrTfBeats  := r.WrMaxBeats;
287	            v.WrTfIsLast := '0';
288	          else
289	            v.WrTfBeats  := r.WrBeats(BeatsBits_c - 1 downto 0);
290	            v.WrTfIsLast := '1';
291	          end if;
292	          v.WrTfVld         := '1';
293	          v.WriteTfGenState := WriteTf_s;
294	
295	        when WriteTf_s =>
296	          if (r.WrTfVld = '1') and (r.AwFsmRdy = '1') then
297	            v.WrTfVld := '0';
298	            v.WrBeats := r.WrBeats - r.WrTfBeats;
299	            v.WrAddr  := r.WrAddr + 2**UnusedAddrBits_c * r.WrTfBeats;
300	            if r.WrTfIsLast = '1' then
301	              v.WriteTfGenState := Idle_s;
302	            else
303	              v.WriteTfGenState := MaxCalc_s;
304	            end if;
305	          end if;
306	
307	        when others => null;
308	      end case;
309	
310	      -- *** AW Command Generation ***
311	      v.AwCmdSent      := '0';
312	      case r.AwFsm is
313	        when Idle_s =>
314	          if ((r.WrLowLat = '1') or (r.WrBeatsNoCmd >= signed('0' & r.WrTfBeats))) and (r.WrOpenTrans < axi_max_open_transactions_g) and (r.WrTfVld = '1') then
315	            v.AwFsmRdy := '1';
316	          end if;
317	          if (r.AwFsmRdy = '1') and (r.WrTfVld = '1') then
318	            v.AwFsmRdy      := '0';
319	            v.m_axi_awaddr  := std_logic_vector(r.WrAddr);
320	            Stdlv9Bit_v     := std_logic_vector(resize(r.WrTfBeats - 1, 9));
321	            v.m_axi_awlen   := Stdlv9Bit_v(7 downto 0);
322	            v.m_axi_awvalid := '1';
323	            v.AwFsm         := Wait_s;
324	            v.AwCmdSent     := '1';
325	            v.AwCmdSize     := r.WrTfBeats;
326	            v.AwCmdSizeMin1 := r.WrTfBeats - 1;
327	          end if;
328	
329	        when Wait_s =>
330	          if m_axi_awready = '1' then
331	            v.WrOpenTrans   := r.WrOpenTrans + 1;
332	            v.m_axi_awvalid := '0';
333	            v.AwFsm         := Idle_s;
334	          end if;
335	
336	        when others => null;
337	      end case;
338	      -- Update counter for FIFO entries that were not yet announced in a command
339	      -- .. Implementation is a bit weird for timing optimization reasons.
340	      -- Use registered WDataFifoWrite: This helps with timing and it does not introduce any risk since
341	      -- .. the decrement is still done immediately, the increment is delayed by one clock cycle. So worst
342	      -- .. case a High-Latency transfer is delayed by one cycle which is acceptable.
343	      v.WDataFifoWrite := WrData_Rdy_I and wr_vld_i;
344	      if r.AwCmdSent = '1' then
345	        if r.WDataFifoWrite = '1' then
346	          v.WrBeatsNoCmd := r.WrBeatsNoCmd - signed('0' & r.AwCmdSizeMin1); -- Decrement by size and increment by one (timing opt)
347	        else
348	          v.WrBeatsNoCmd := r.WrBeatsNoCmd - signed('0' & r.AwCmdSize);
349	        end if;
350	      elsif r.WDataFifoWrite = '1' then
351	        v.WrBeatsNoCmd := r.WrBeatsNoCmd + 1;
352	      end if;
353	
354	      -- *** W Data Generation ***
355	      WDataTransfer_v := (r.WDataEna = '1') and (WrDataFifoOVld = '1') and (WrDataFifoORdy = '1');
356	      v.WDataFifoRd   := '0';
357	      StartWBurst_v   := false;
358	      case r.WFsm is
359	        when Idle_s =>
360	          if WrTransFifoOutVld = '1' then
361	            StartWBurst_v := true;      -- shared code
362	          end if;
363	
364	        when NonLast_s =>
365	          if WDataTransfer_v then
366	            if r.WDataBeats = 2 then
367	              v.m_axi_wlast := '1';
368	              v.WFsm        := Last_s;
369	            end if;
370	            v.WDataBeats := r.WDataBeats - 1;
371	          end if;
372	
373	        when Last_s =>
374	          if WDataTransfer_v then
375	            -- Immediately start next transfer
376	            -- .. WDataFifoRd is checked to leave time for the FIFO to complete the read in case of single cycle transfers
377	            if (WrTransFifoOutVld = '1') and (r.WDataFifoRd = '0') then
378	              StartWBurst_v := true;    -- shared code
379	              -- End of transfer without a next one back-to-back
380	            else
381	              v.WDataEna    := '0';
382	              v.WFsm        := Idle_s;
383	              v.m_axi_wlast := '0';
384	            end if;
385	          end if;
386	
387	        when others => null;
388	      end case;
389	      -- implementation of shared code
390	      if StartWBurst_v then
391	        v.WDataFifoRd := '1';
392	        v.WDataEna    := '1';
393	        v.WDataBeats  := unsigned(WrTransFifoBeats);
394	        if unsigned(WrTransFifoBeats) = 1 then
395	          v.m_axi_wlast := '1';
396	          v.WFsm        := Last_s;
397	        else
398	          v.m_axi_wlast := '0';
399	          v.WFsm        := NonLast_s;
400	        end if;
401	      end if;
402	
403	      -- *** W Response Generation ***
404	      v.wr_done_o  := '0';
405	      v.wr_error_o := '0';
406	      if m_axi_bvalid = '1' then
407	        assert WrRespFifoVld = '1' report "###ERROR###: psi_common_axi_master_simple internal error --> WrRespFifo Empty" severity error;
408	        v.WrOpenTrans := v.WrOpenTrans - 1; -- Use v. because it may have been modified above and this modification has not to be overriden
409	        if WrRespIsLast = '1' then
410	          if (m_axi_bresp /= Axi_Resp_Okay_c) then
411	            v.wr_error_o := '1';
412	          else
413	            v.wr_error_o  := r.WrRespError;
414	            v.wr_done_o   := not r.WrRespError;
415	            v.WrRespError := '0';
416	          end if;
417	        elsif m_axi_bresp /= Axi_Resp_Okay_c then
418	          v.WrRespError := '1';
419	        end if;
420	      end if;
421	
422	    end if;
423	
424	    --------------------------------------------------------------------------
425	    -- Read Related Code
426	    --------------------------------------------------------------------------
427	    if impl_read_g then
428	
429	      -- *** Read Transfer Generation ***
430	      RdMax4kBeats_v := (others => '0');
431	      case r.ReadTfGenState is
432	        when Idle_s =>
433	          v.cmd_rd_rdy_o := '1';
434	          if (r.cmd_rd_rdy_o = '1') and (cmd_rd_vld_i = '1') then
435	            v.cmd_rd_rdy_o   := '0';
436	            v.RdAddr         := unsigned(AddrMasked_f(cmd_rd_addr_i));
437	            v.RdBeats        := unsigned(cmd_rd_size_o);
438	            v.RdLowLat       := cmd_rd_low_lat_i;
439	            v.ReadTfGenState := MaxCalc_s;
440	          end if;
441	
442	        when MaxCalc_s =>
443	          RdMax4kBeats_v   := resize(unsigned('0' & not r.RdAddr(11 downto UnusedAddrBits_c)) + 1, RdMax4kBeats_v'length);
444	          if RdMax4kBeats_v > axi_max_beats_g then
445	            v.RdMaxBeats := to_unsigned(axi_max_beats_g, BeatsBits_c);
446	          else
447	            v.RdMaxBeats := RdMax4kBeats_v(BeatsBits_c - 1 downto 0);
448	          end if;
449	          v.ReadTfGenState := GenTf_s;
450	
451	        when GenTf_s =>
452	          if (r.RdMaxBeats < r.RdBeats) then
453	            v.RdTfBeats  := r.RdMaxBeats;
454	            v.RdTfIsLast := '0';
455	          else
456	            v.RdTfBeats  := r.RdBeats(BeatsBits_c - 1 downto 0);
457	            v.RdTfIsLast := '1';
458	          end if;
459	          v.RdTfVld        := '1';
460	          v.ReadTfGenState := WriteTf_s;
461	
462	        when WriteTf_s =>
463	          if (r.RdTfVld = '1') and (r.ArFsmRdy = '1') then
464	            v.RdTfVld := '0';
465	            v.RdBeats := r.RdBeats - r.RdTfBeats;
466	            v.RdAddr  := r.RdAddr + 2**UnusedAddrBits_c * r.RdTfBeats;
467	            if r.RdTfIsLast = '1' then
468	              v.ReadTfGenState := Idle_s;
469	            else
470	              v.ReadTfGenState := MaxCalc_s;
471	            end if;
472	          end if;
473	
474	        when others => null;
475	      end case;
476	
477	      -- *** AR Command Generation ***
478	      v.ArCmdSent     := '0';
479	      case r.ArFsm is
480	        when Idle_s =>
481	          if ((r.RdLowLat = '1') or (r.RdFifoSpaceFree >= signed('0' & r.RdTfBeats))) and (r.RdOpenTrans < axi_max_open_transactions_g) and (r.RdTfVld = '1') then
482	            v.ArFsmRdy := '1';
483	          end if;
484	          if (r.ArFsmRdy = '1') and (r.RdTfVld = '1') then
485	            v.ArFsmRdy      := '0';
486	            v.m_axi_araddr  := std_logic_vector(r.RdAddr);
487	            Stdlv9Bit_v     := std_logic_vector(resize(r.RdTfBeats - 1, 9));
488	            v.m_axi_arlen   := Stdlv9Bit_v(7 downto 0);
489	            v.m_axi_arvalid := '1';
490	            v.ArFsm         := Wait_s;
491	            v.ArCmdSent     := '1';
492	            v.ArCmdSize     := r.RdTfBeats;
493	            v.ArCmdSizeMin1 := r.RdTfBeats - 1;
494	          end if;
495	
496	        when Wait_s =>
497	          if m_axi_arready = '1' then
498	            v.RdOpenTrans   := r.RdOpenTrans + 1;
499	            v.m_axi_arvalid := '0';
500	            v.ArFsm         := Idle_s;
501	          end if;
502	
503	        when others => null;
504	      end case;
505	      -- Update counter for FIFO entries that were not yet announced in a command
506	      -- .. Implementation is a bit weird for timing optimization reasons.
507	      -- Use registered RDataFifoRead: This helps with timing and it does not introduce any risk since
508	      -- .. the decrement is still done immediately, the increment is delayed by one clock cycle. So worst
509	      -- .. case a High-Latency transfer is delayed by one cycle which is acceptable.
510	      v.RDataFifoRead := rd_rdy_i and RdDat_Vld_I;
511	      if r.ArCmdSent = '1' then
512	        if r.RDataFifoRead = '1' then
513	          v.RdFifoSpaceFree := r.RdFifoSpaceFree - signed('0' & r.ArCmdSizeMin1); -- Decrement by size and increment by one (timing opt)
514	        else
515	          v.RdFifoSpaceFree := r.RdFifoSpaceFree - signed('0' & r.ArCmdSize);
516	        end if;
517	      elsif r.RDataFifoRead = '1' then
518	        v.RdFifoSpaceFree := r.RdFifoSpaceFree + 1;
519	      end if;
520	
521	      -- *** R Response Generation ***
522	      v.rd_done_o  := '0';
523	      v.rd_error_o := '0';
524	      if RdRespLast = '1' then
525	        assert RdRespFifoVld = '1' report "###ERROR###: psi_common_axi_master_simple internal error --> RdRespFifo Empty" severity error;
526	        v.RdOpenTrans := v.RdOpenTrans - 1; -- Use v. because it may have been modified above and this modification has not to be overriden
527	        if RdRespIsLast = '1' then
528	          if (m_axi_rresp /= Axi_Resp_Okay_c) then
529	            v.rd_error_o := '1';
530	          else
531	            v.rd_error_o  := r.RdRespError;
532	            v.rd_done_o   := not r.RdRespError;
533	            v.RdRespError := '0';
534	          end if;
535	        elsif m_axi_rresp /= Axi_Resp_Okay_c then
536	          v.RdRespError := '1';
537	        end if;
538	      end if;
539	
540	    end if;
541	
542	    -- *** Update Signal ***
543	    r_next <= v;
544	  end process;
545	
546	  ------------------------------------------------------------------------------
547	  -- Registered Process
548	  ------------------------------------------------------------------------------
549	  p_reg : process(m_axi_aclk)
550	  begin
551	    if rising_edge(m_axi_aclk) then
552	      r <= r_next;
553	      if m_axi_aresetn = '0' then
554	        -- *** Write Related Registers ***
555	        if impl_write_g then
556	          r.cmd_wr_rdy_o    <= '0';
557	          r.WriteTfGenState <= Idle_s;
558	          r.WrTfVld         <= '0';
559	          r.AwFsm           <= Idle_s;
560	          r.AwFsmRdy        <= '0';
561	          r.AwCmdSent       <= '0';
562	          r.m_axi_awvalid   <= '0';
563	          r.WDataFifoRd     <= '0';
564	          r.WDataEna        <= '0';
565	          r.WrOpenTrans     <= 0;
566	          r.WrRespError     <= '0';
567	          r.wr_done_o       <= '0';
568	          r.wr_error_o      <= '0';
569	          r.WrBeatsNoCmd    <= (others => '0');
570	          r.WFsm            <= Idle_s;
571	          r.WDataFifoWrite  <= '0';
572	        end if;
573	        -- *** Read Related Registers ***
574	        if impl_read_g then
575	          r.cmd_rd_rdy_o    <= '0';
576	          r.ReadTfGenState  <= Idle_s;
577	          r.RdTfVld         <= '0';
578	          r.ArFsmRdy        <= '0';
579	          r.ArCmdSent       <= '0';
580	          r.m_axi_arvalid   <= '0';
581	          r.ArFsm           <= Idle_s;
582	          r.RdOpenTrans     <= (others => '0');
583	          r.RdRespError     <= '0';
584	          r.rd_done_o       <= '0';
585	          r.rd_error_o      <= '0';
586	          r.RdFifoSpaceFree <= to_signed(data_fifo_depth_g, r.RdFifoSpaceFree'length);
587	          r.RDataFifoRead   <= '0';
588	        end if;
589	      end if;
590	    end if;
591	  end process;
592	
593	  ------------------------------------------------------------------------------
594	  -- Outputs
595	  ------------------------------------------------------------------------------
596	  cmd_wr_rdy_o  <= r.cmd_wr_rdy_o;
597	  m_axi_awaddr  <= r.m_axi_awaddr;
598	  m_axi_awlen   <= r.m_axi_awlen;
599	  m_axi_awvalid <= r.m_axi_awvalid;
600	  m_axi_wlast   <= r.m_axi_wlast;
601	  wr_done_o     <= r.wr_done_o;
602	  wr_error_o    <= r.wr_error_o;
603	  cmd_rd_rdy_o  <= r.cmd_rd_rdy_o;
604	  m_axi_araddr  <= r.m_axi_araddr;
605	  m_axi_arlen   <= r.m_axi_arlen;
606	  m_axi_arvalid <= r.m_axi_arvalid;
607	  rd_done_o     <= r.rd_done_o;
608	  rd_error_o    <= r.rd_error_o;
609	
610	  ------------------------------------------------------------------------------
611	  -- Constant Outputs
612	  ------------------------------------------------------------------------------
613	  m_axi_awsize  <= std_logic_vector(to_unsigned(log2(axi_data_width_g / 8), 3));
614	  m_axi_arsize  <= std_logic_vector(to_unsigned(log2(axi_data_width_g / 8), 3));
615	  m_axi_awburst <= Axi_BurstType_Incr_c;
616	  m_axi_arburst <= Axi_BurstType_Incr_c;
617	  m_axi_awcache <= "0011";              -- According AXI reference guide
618	  m_axi_arcache <= "0011";              -- According AXI reference guide
619	  m_axi_awprot  <= "000";               -- According AXI reference guide
620	  m_axi_arprot  <= "000";               -- According AXI reference guide
621	  m_axi_awlock  <= '0';                 -- Exclusive access support not implemented
622	  m_axi_arlock  <= '0';                 -- Exclusive access support not implemented
623	  m_axi_bready  <= '1' when impl_write_g else '0';
624	
625	  ------------------------------------------------------------------------------
626	  -- Instantiations
627	  ------------------------------------------------------------------------------
628	
629	  -- *** Write FIFOs ***
630	  g_write : if impl_write_g generate
631	
632	    -- FIFO for data transfer FSM
633	    WrTransFifoInVld <= r.AwFsmRdy and r.WrTfVld;
634	    i_fifo_wr_trans : entity work.psi_common_sync_fifo
635	      generic map(
636	        rst_pol_g      => '0',
637	        width_g        => BeatsBits_c,
638	        depth_g        => axi_max_open_transactions_g,
639	        alm_full_on_g  => false,
640	        alm_empty_on_g => false,
641	        ram_style_g    => "auto",
642	        ram_behavior_g => ram_behavior_g)
643	      port map(
644	        clk_i => m_axi_aclk,
645	        rst_i => m_axi_aresetn,
646	        dat_i => std_logic_vector(r.WrTfBeats),
647	        vld_i => WrTransFifoInVld,
648	        rdy_o => open,                  -- Not required since maximum of open transactions is limitted
649	        dat_o => WrTransFifoBeats,
650	        vld_o => WrTransFifoOutVld,
651	        rdy_i => r.WDataFifoRd);
652	
653	    -- Write Data FIFO
654	    b_fifo_wr_data : block
655	      signal InData  : std_logic_vector(wr_dat_i'length + wr_data_be_i'length - 1 downto 0);
656	      signal OutData : std_logic_vector(InData'range);
657	    begin
658	      InData(wr_dat_i'high downto wr_dat_i'low)                          <= wr_dat_i;
659	      InData(wr_dat_i'high + wr_data_be_i'length downto wr_dat_i'high + 1) <= wr_data_be_i;
660	      i_fifo_wr_data : entity work.psi_common_sync_fifo
661	        generic map(
662	          width_g        => wr_dat_i'length + wr_data_be_i'length,
663	          depth_g        => data_fifo_depth_g,
664	          alm_full_on_g  => false,
665	          alm_empty_on_g => false,
666	          ram_style_g    => "auto",
667	          ram_behavior_g => ram_behavior_g,
668	          rst_pol_g      => '0')
669	        port map(
670	          clk_i => m_axi_aclk,
671	          rst_i => m_axi_aresetn,
672	          dat_i => InData,
673	          vld_i => wr_vld_i,
674	          rdy_o => WrData_Rdy_I,
675	          dat_o => OutData,
676	          vld_o => WrDataFifoOVld,
677	          rdy_i => WrDataFifoORdy
678	        );
679	      m_axi_wdata                                                        <= OutData(wr_dat_i'high downto wr_dat_i'low);
680	      m_axi_wstrb                                                        <= OutData(wr_dat_i'high + wr_data_be_i'length downto wr_dat_i'high + 1);
681	
682	      m_axi_wvalid   <= WrDataFifoOVld and r.WDataEna;
683	      WrDataFifoORdy <= m_axi_wready and r.WDataEna;
684	
685	      wr_rdy_o <= WrData_Rdy_I;
686	    end block;
687	
688	    -- FIFO for write response FSM
689	    i_fifo_wr_resp : entity work.psi_common_sync_fifo
690	      generic map(
691	        width_g        => 1,
692	        depth_g        => axi_max_open_transactions_g,
693	        alm_full_on_g  => false,
694	        alm_empty_on_g => false,
695	        ram_style_g    => "auto",
696	        ram_behavior_g => ram_behavior_g,
697	        rst_pol_g      => '0')
698	      port map(
699	        clk_i    => m_axi_aclk,
700	        rst_i    => m_axi_aresetn,
701	        dat_i(0) => r.WrTfIsLast,
702	        vld_i    => WrTransFifoInVld,
703	        rdy_o    => open,               -- Not required since maximum of open transactions is limitted
704	        dat_o(0) => WrRespIsLast,
705	        vld_o    => WrRespFifoVld,
706	        rdy_i    => m_axi_bvalid);
707	  end generate;
708	
709	  -- Tie signals to ground if read not implemented
710	  g_nwrite : if not impl_write_g generate
711	    m_axi_wstrb  <= (others => '0');
712	    m_axi_wdata  <= (others => '0');
713	    m_axi_wvalid <= '0';
714	    wr_rdy_o     <= '0';
715	  end generate;
716	
717	  -- *** Read FIFOs ***
718	  g_read : if impl_read_g generate
719	
720	    -- Read Data FIFO
721	    b_fifo_rd_data : block
722	    begin
723	      i_fifo_wr_data : entity work.psi_common_sync_fifo
724	        generic map(
725	          width_g        => rd_dat_o'length,
726	          depth_g        => data_fifo_depth_g,
727	          alm_full_on_g  => false,
728	          alm_empty_on_g => false,
729	          ram_style_g    => "auto",
730	          ram_behavior_g => ram_behavior_g,
731	          rst_pol_g      => '0'
732	        )
733	        port map(
734	          clk_i => m_axi_aclk,
735	          rst_i => m_axi_aresetn,
736	          dat_i => m_axi_rdata,
737	          vld_i => m_axi_rvalid,
738	          rdy_o => M_Axi_RReady_I,
739	          dat_o => rd_dat_o,
740	          vld_o => RdDat_Vld_I,
741	          rdy_i => rd_rdy_i
742	        );
743	
744	      rd_vld_o     <= RdDat_Vld_I;
745	      m_axi_rready <= M_Axi_RReady_I;
746	    end block;
747	
748	    -- FIFO for read response FSM
749	    RdTransFifoInVld <= r.ArFsmRdy and r.RdTfVld;
750	    RdRespLast       <= m_axi_rvalid and M_Axi_RReady_I and m_axi_rlast;
751	    i_fifo_rd_resp : entity work.psi_common_sync_fifo
752	      generic map(
753	        width_g        => 1,
754	        depth_g        => axi_max_open_transactions_g,
755	        alm_full_on_g  => false,
756	        alm_empty_on_g => false,
757	        ram_style_g    => "auto",
758	        ram_behavior_g => ram_behavior_g,
759	        rst_pol_g      => '0'
760	      )
761	      port map(
762	        clk_i    => m_axi_aclk,
763	        rst_i    => m_axi_aresetn,
764	        dat_i(0) => r.RdTfIsLast,
765	        vld_i    => RdTransFifoInVld,
766	        rdy_o    => open,               -- Not required since maximum of open transactions is limitted
767	        dat_o(0) => RdRespIsLast,
768	        vld_o    => RdRespFifoVld,
769	        rdy_i    => RdRespLast
770	      );
771	
772	  end generate;
773	
774	  -- Tie signals to ground if read not implemented
775	  g_nread : if not impl_read_g generate
776	    m_axi_rready <= '0';
777	    rd_dat_o     <= (others => '0');
778	    rd_vld_o     <= '0';
779	  end generate;
780	
781	end architecture;

file.content:
------------------------------------------------------------------------------
--  Copyright (c) 2019 by Paul Scherrer Institute, Switzerland
--  All rights reserved.
--  Authors: Oliver Bruendler
------------------------------------------------------------------------------

------------------------------------------------------------------------------
-- Description
------------------------------------------------------------------------------
-- This entity implements a simple AXI master. Simple means: It does not
-- support any unaligned reads/writes and it does not do any width conversions.
-- It just executes the transfers requested and splits them into multiple AXI
-- transactions in order to not burst over 4k boundaries and respect the maximum
-- transaction size.

library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

use work.psi_common_math_pkg.all;
use work.psi_common_logic_pkg.all;
--@fomratter:off
entity psi_common_axi_master_simple is
  generic(
    axi_addr_width_g             : natural range 12 to 64  := 32;   -- $$ constant=32 $$
    axi_data_width_g             : natural range 8 to 1024 := 32;   -- $$ constant=16 $$
    axi_max_beats_g              : natural range 1 to 256  := 256;  -- $$ constant=16 $$
    axi_max_open_transactions_g  : natural range 1 to 8    := 8;    -- $$ constant=3 $$
    user_transaction_size_bits_g : natural                 := 32;   -- $$ constant=10 $$
    data_fifo_depth_g            : natural                 := 1024; -- $$ constant=10 $$
    impl_read_g                  : boolean                 := true; -- $$ export=true $$
    impl_write_g                 : boolean                 := true; -- $$ export=true $$
    ram_behavior_g               : string                  := "RBW" -- $$ constant="RBW" $$
  );
  port(
    -- Control Signals
    m_axi_aclk       : in  std_logic;                                                                       -- $$ type=clk; freq=100e6 $$
    m_axi_aresetn    : in  std_logic;                                                                       -- $$ type=rst; clk=M_Axi_Aclk; lowactive=true $$
    -- User Command Interface
    cmd_wr_addr_i    : in  std_logic_vector(axi_addr_width_g - 1 downto 0)             := (others => '0');  -- $$ proc=user_cmd $$
    cmd_wr_size_i    : in  std_logic_vector(user_transaction_size_bits_g - 1 downto 0) := (others => '0');  -- $$ proc=user_cmd $$
    cmd_wr_low_lat_i : in  std_logic                                                   := '0';              -- $$ proc=user_cmd $$
    cmd_wr_vld_i     : in  std_logic                                                   := '0';              -- $$ proc=user_cmd $$
    cmd_wr_rdy_o     : out std_logic;                                                                       -- $$ proc=user_cmd $$
    -- User Command Interface
    cmd_rd_addr_i    : in  std_logic_vector(axi_addr_width_g - 1 downto 0)             := (others => '0');  -- $$ proc=user_cmd $$
    cmd_rd_size_o    : in  std_logic_vector(user_transaction_size_bits_g - 1 downto 0) := (others => '0');  -- $$ proc=user_cmd $$
    cmd_rd_low_lat_i : in  std_logic                                                   := '0';              -- $$ proc=user_cmd $$
    cmd_rd_vld_i     : in  std_logic                                                   := '0';              -- $$ proc=user_cmd $$
    cmd_rd_rdy_o     : out std_logic;                                                                       -- $$ proc=user_cmd $$
    -- Write Data
    wr_dat_i         : in  std_logic_vector(axi_data_width_g - 1 downto 0)             := (others => '0');  -- $$ proc=user_data $$
    wr_data_be_i     : in  std_logic_vector(axi_data_width_g / 8 - 1 downto 0)         := (others => '0');  -- $$ proc=user_data $$
    wr_vld_i         : in  std_logic                                                   := '0';              -- $$ proc=user_data $$
    wr_rdy_o         : out std_logic;                                                                       -- $$ proc=user_data $$
    -- Read Data
    rd_dat_o         : out std_logic_vector(axi_data_width_g - 1 downto 0);                                 -- $$ proc=user_data $$
    rd_vld_o         : out std_logic;                                                                       -- $$ proc=user_data $$
    rd_rdy_i         : in  std_logic                                                   := '0';              -- $$ proc=user_data $$
    -- Response
    wr_done_o        : out std_logic;                                                                       -- $$ proc=user_resp $$
    wr_error_o       : out std_logic;                                                                       -- $$ proc=user_resp $$
    rd_done_o        : out std_logic;                                                                       -- $$ proc=user_resp $$
    rd_error_o       : out std_logic;                                                                       -- $$ proc=user_resp $$
    -- AXI Address Write Channel
    m_axi_awaddr     : out std_logic_vector(axi_addr_width_g - 1 downto 0);                                 -- $$ proc=axi $$
    m_axi_awlen      : out std_logic_vector(7 downto 0);                                                    -- $$ proc=axi $$
    m_axi_awsize     : out std_logic_vector(2 downto 0);                                                    -- $$ proc=axi $$
    m_axi_awburst    : out std_logic_vector(1 downto 0);                                                    -- $$ proc=axi $$
    m_axi_awlock     : out std_logic;                                                                       -- $$ proc=axi $$
    m_axi_awcache    : out std_logic_vector(3 downto 0);                                                    -- $$ proc=axi $$
    m_axi_awprot     : out std_logic_vector(2 downto 0);                                                    -- $$ proc=axi $$
    m_axi_awvalid    : out std_logic;                                                                       -- $$ proc=axi $$
    m_axi_awready    : in  std_logic                                                   := '0';              -- $$ proc=axi $$
    -- AXI Write Data Channel                                                                               -- $$ proc=axi $$
    m_axi_wdata      : out std_logic_vector(axi_data_width_g - 1 downto 0);                                 -- $$ proc=axi $$
    m_axi_wstrb      : out std_logic_vector(axi_data_width_g / 8 - 1 downto 0);                             -- $$ proc=axi $$
    m_axi_wlast      : out std_logic;                                                                       -- $$ proc=axi $$
    m_axi_wvalid     : out std_logic;                                                                       -- $$ proc=axi $$
    m_axi_wready     : in  std_logic                                                   := '0';              -- $$ proc=axi $$
    -- AXI Write Response Channel
    m_axi_bresp      : in  std_logic_vector(1 downto 0)                                := (others => '0');  -- $$ proc=axi $$
    m_axi_bvalid     : in  std_logic                                                   := '0';              -- $$ proc=axi $$
    m_axi_bready     : out std_logic;                                                                       -- $$ proc=axi $$
    -- AXI Read Address Channel
    m_axi_araddr     : out std_logic_vector(axi_addr_width_g - 1 downto 0);                                 -- $$ proc=axi $$
    m_axi_arlen      : out std_logic_vector(7 downto 0);                                                    -- $$ proc=axi $$
    m_axi_arsize     : out std_logic_vector(2 downto 0);                                                    -- $$ proc=axi $$
    m_axi_arburst    : out std_logic_vector(1 downto 0);                                                    -- $$ proc=axi $$
    m_axi_arlock     : out std_logic;                                                                       -- $$ proc=axi $$
    m_axi_arcache    : out std_logic_vector(3 downto 0);                                                    -- $$ proc=axi $$
    m_axi_arprot     : out std_logic_vector(2 downto 0);                                                    -- $$ proc=axi $$
    m_axi_arvalid    : out std_logic;                                                                       -- $$ proc=axi $$
    m_axi_arready    : in  std_logic                                                   := '0';              -- $$ proc=axi $$
    -- AXI Read Data Channel
    m_axi_rdata      : in  std_logic_vector(axi_data_width_g - 1 downto 0)             := (others => '0');  -- $$ proc=axi $$
    m_axi_rresp      : in  std_logic_vector(1 downto 0)                                := (others => '0');  -- $$ proc=axi $$
    m_axi_rlast      : in  std_logic                                                   := '0';              -- $$ proc=axi $$
    m_axi_rvalid     : in  std_logic                                                   := '0';              -- $$ proc=axi $$
    m_axi_rready     : out std_logic                                                                        -- $$ proc=axi $$
  );
end entity;
--@fomratter:on

architecture rtl of psi_common_axi_master_simple is

  ------------------------------------------------------------------------------
  -- Constants
  ------------------------------------------------------------------------------
  constant Axi_BurstType_Incr_c : std_logic_vector(1 downto 0) := "01";
  constant Axi_Resp_Okay_c      : std_logic_vector(1 downto 0) := "00";
  constant UnusedAddrBits_c     : natural                      := log2(axi_data_width_g / 8);

  constant BeatsBits_c       : natural := log2ceil(axi_max_beats_g + 1);
  subtype Trans_AddrRange_c is natural range cmd_wr_addr_i'high downto 0;
  subtype Trans_BurstRange_c is natural range BeatsBits_c + Trans_AddrRange_c'high downto Trans_AddrRange_c'high + 1;
  constant Trans_LowLatIdx_c : natural := Trans_BurstRange_c'high + 1;
  constant Trans_Size_c      : natural := Trans_LowLatIdx_c + 1;
  constant MaxBeatsNoCmd_c   : natural := max(axi_max_beats_g * axi_max_open_transactions_g, data_fifo_depth_g);

  ------------------------------------------------------------------------------
  -- Type
  ------------------------------------------------------------------------------
  type WriteTfGen_s is (Idle_s, MaxCalc_s, GenTf_s, WriteTf_s);
  type ReadTfGen_s is (Idle_s, MaxCalc_s, GenTf_s, WriteTf_s);
  type AwFsm_s is (Idle_s, Wait_s);
  type ArFsm_s is (Idle_s, Wait_s);
  type WFsm_s is (Idle_s, NonLast_s, Last_s);

  ------------------------------------------------------------------------------
  -- Functions
  ------------------------------------------------------------------------------
  function AddrMasked_f(Addr : in std_logic_vector) return std_logic_vector is
    variable Masked_v : std_logic_vector(Addr'range);
  begin
    Masked_v                                := Addr;
    Masked_v(UnusedAddrBits_c - 1 downto 0) := (others => '0');
    return Masked_v;
  end function;

  ------------------------------------------------------------------------------
  -- Two Process Record
  ------------------------------------------------------------------------------
  type two_process_r is record

    -- *** Write Related Registers ***
    -- Command Interface
    cmd_wr_rdy_o    : std_logic;
    wr_error_o      : std_logic;
    wr_done_o       : std_logic;
    -- Generate Write Transactions
    WriteTfGenState : WriteTfGen_s;
    WrAddr          : unsigned(cmd_wr_addr_i'range);
    WrBeats         : unsigned(cmd_wr_size_i'range);
    WrLowLat        : std_logic;
    WrMaxBeats      : unsigned(BeatsBits_c - 1 downto 0);
    WrTfBeats       : unsigned(BeatsBits_c - 1 downto 0);
    WrTfVld         : std_logic;
    WrTfIsLast      : std_logic;
    -- Execute Aw Commands
    AwFsm           : AwFsm_s;
    AwFsmRdy        : std_logic;
    AwCmdSent       : std_logic;
    AwCmdSize       : unsigned(BeatsBits_c - 1 downto 0);
    AwCmdSizeMin1   : unsigned(BeatsBits_c - 1 downto 0); -- 	AwCmdSize-1 for timing optimization reasons
    WDataFifoWrite  : std_logic;
    -- Execute W Data
    WFsm            : WFsm_s;
    WDataFifoRd     : std_logic;
    WDataEna        : std_logic;
    WDataBeats      : unsigned(BeatsBits_c - 1 downto 0);
    -- Write Response
    WrRespError     : std_logic;
    -- Write General
    WrOpenTrans     : integer range -1 to axi_max_open_transactions_g;
    WrBeatsNoCmd    : signed(log2ceil(MaxBeatsNoCmd_c + 1) downto 0);
    -- AXI Signals
    m_axi_awaddr    : std_logic_vector(m_axi_awaddr'range);
    m_axi_awlen     : std_logic_vector(m_axi_awlen'range);
    m_axi_awvalid   : std_logic;
    m_axi_wlast     : std_logic;

    -- *** Read Related Registers ***
    -- Command Interface
    cmd_rd_rdy_o    : std_logic;
    rd_error_o      : std_logic;
    rd_done_o       : std_logic;
    -- Generate Read Transactions
    ReadTfGenState  : ReadTfGen_s;
    RdAddr          : unsigned(cmd_rd_addr_i'range);
    RdBeats         : unsigned(cmd_rd_size_o'range);
    RdLowLat        : std_logic;
    RdMaxBeats      : unsigned(BeatsBits_c - 1 downto 0);
    RdTfBeats       : unsigned(BeatsBits_c - 1 downto 0);
    RdTfVld         : std_logic;
    RdTfIsLast      : std_logic;
    -- Execute Ar Commands
    ArFsm           : ArFsm_s;
    ArFsmRdy        : std_logic;
    ArCmdSent       : std_logic;
    ArCmdSize       : unsigned(BeatsBits_c - 1 downto 0);
    ArCmdSizeMin1   : unsigned(BeatsBits_c - 1 downto 0); -- 	ArCmdSize-1 for timing optimization reasons
    RDataFifoRead   : std_logic;
    -- Write Response
    RdRespError     : std_logic;
    -- Read General
    RdOpenTrans     : unsigned(log2ceil(axi_max_open_transactions_g + 1) - 1 downto 0);
    RdFifoSpaceFree : signed(log2ceil(MaxBeatsNoCmd_c + 1) downto 0);
    -- AXI Signals
    m_axi_araddr    : std_logic_vector(m_axi_araddr'range);
    m_axi_arlen     : std_logic_vector(m_axi_arlen'range);
    m_axi_arvalid   : std_logic;

  end record;
  signal r, r_next : two_process_r;

  ------------------------------------------------------------------------------
  -- Instantiation Signals
  ------------------------------------------------------------------------------
 -- signal Rst               : std_logic;
  signal WrDataFifoORdy    : std_logic;
  signal WrDataFifoOVld    : std_logic;
  signal WrTransFifoInVld  : std_logic;
  signal WrTransFifoBeats  : std_logic_vector(BeatsBits_c - 1 downto 0);
  signal WrTransFifoOutVld : std_logic;
  signal WrRespIsLast      : std_logic;
  signal WrRespFifoVld     : std_logic;
  signal WrData_Rdy_I      : std_logic;
  signal RdTransFifoInVld  : std_logic;
  signal RdRespIsLast      : std_logic;
  signal RdRespFifoVld     : std_logic;
  signal RdDat_Vld_I       : std_logic;
  signal RdRespLast        : std_logic;
  signal M_Axi_RReady_I    : std_logic;

begin

  ------------------------------------------------------------------------------
  -- Assertions
  ------------------------------------------------------------------------------
  assert axi_data_width_g mod 8 = 0 report "###ERROR###: psi_common_axi_master_simple axi_data_width_g must be a multiple of 8" severity failure;

  ------------------------------------------------------------------------------
  -- Combinatorial Process
  ------------------------------------------------------------------------------
  p_comb : process(r, m_axi_awready, m_axi_bvalid, m_axi_bresp, WrDataFifoORdy, WrDataFifoOVld, WrTransFifoOutVld, WrTransFifoBeats, WrRespIsLast, WrRespFifoVld, cmd_wr_addr_i, cmd_wr_size_i, cmd_wr_low_lat_i, cmd_wr_vld_i, wr_vld_i, WrData_Rdy_I, m_axi_arready, RdRespIsLast, RdRespFifoVld, RdRespLast, cmd_rd_addr_i, cmd_rd_size_o, cmd_rd_low_lat_i, cmd_rd_vld_i, rd_rdy_i, RdDat_Vld_I)
    variable v               : two_process_r;
    variable WrMax4kBeats_v  : unsigned(13 - UnusedAddrBits_c downto 0);
    variable RdMax4kBeats_v  : unsigned(13 - UnusedAddrBits_c downto 0);
    variable Stdlv9Bit_v     : std_logic_vector(8 downto 0);
    variable WDataTransfer_v : boolean;
    variable StartWBurst_v   : boolean := true;
  begin
    -- *** Keep two process variables stable ***
    v := r;

    --------------------------------------------------------------------------
    -- Write Related Code
    --------------------------------------------------------------------------
    if impl_write_g then

      -- *** Write Transfer Generation ***
      WrMax4kBeats_v := (others => '0');
      case r.WriteTfGenState is
        when Idle_s =>
          v.cmd_wr_rdy_o := '1';
          if (r.cmd_wr_rdy_o = '1') and (cmd_wr_vld_i = '1') then
            v.cmd_wr_rdy_o    := '0';
            v.WrAddr          := unsigned(AddrMasked_f(cmd_wr_addr_i));
            v.WrBeats         := unsigned(cmd_wr_size_i);
            v.WrLowLat        := cmd_wr_low_lat_i;
            v.WriteTfGenState := MaxCalc_s;
          end if;

        when MaxCalc_s =>
          WrMax4kBeats_v    := resize(unsigned('0' & not r.WrAddr(11 downto UnusedAddrBits_c)) + 1, WrMax4kBeats_v'length);
          if WrMax4kBeats_v > axi_max_beats_g then
            v.WrMaxBeats := to_unsigned(axi_max_beats_g, BeatsBits_c);
          else
            v.WrMaxBeats := WrMax4kBeats_v(BeatsBits_c - 1 downto 0);
          end if;
          v.WriteTfGenState := GenTf_s;

        when GenTf_s =>
          if (r.WrMaxBeats < r.WrBeats) then
            v.WrTfBeats  := r.WrMaxBeats;
            v.WrTfIsLast := '0';
          else
            v.WrTfBeats  := r.WrBeats(BeatsBits_c - 1 downto 0);
            v.WrTfIsLast := '1';
          end if;
          v.WrTfVld         := '1';
          v.WriteTfGenState := WriteTf_s;

        when WriteTf_s =>
          if (r.WrTfVld = '1') and (r.AwFsmRdy = '1') then
            v.WrTfVld := '0';
            v.WrBeats := r.WrBeats - r.WrTfBeats;
            v.WrAddr  := r.WrAddr + 2**UnusedAddrBits_c * r.WrTfBeats;
            if r.WrTfIsLast = '1' then
              v.WriteTfGenState := Idle_s;
            else
              v.WriteTfGenState := MaxCalc_s;
            end if;
          end if;

        when others => null;
      end case;

      -- *** AW Command Generation ***
      v.AwCmdSent      := '0';
      case r.AwFsm is
        when Idle_s =>
          if ((r.WrLowLat = '1') or (r.WrBeatsNoCmd >= signed('0' & r.WrTfBeats))) and (r.WrOpenTrans < axi_max_open_transactions_g) and (r.WrTfVld = '1') then
            v.AwFsmRdy := '1';
          end if;
          if (r.AwFsmRdy = '1') and (r.WrTfVld = '1') then
            v.AwFsmRdy      := '0';
            v.m_axi_awaddr  := std_logic_vector(r.WrAddr);
            Stdlv9Bit_v     := std_logic_vector(resize(r.WrTfBeats - 1, 9));
            v.m_axi_awlen   := Stdlv9Bit_v(7 downto 0);
            v.m_axi_awvalid := '1';
            v.AwFsm         := Wait_s;
            v.AwCmdSent     := '1';
            v.AwCmdSize     := r.WrTfBeats;
            v.AwCmdSizeMin1 := r.WrTfBeats - 1;
          end if;

        when Wait_s =>
          if m_axi_awready = '1' then
            v.WrOpenTrans   := r.WrOpenTrans + 1;
            v.m_axi_awvalid := '0';
            v.AwFsm         := Idle_s;
          end if;

        when others => null;
      end case;
      -- Update counter for FIFO entries that were not yet announced in a command
      -- .. Implementation is a bit weird for timing optimization reasons.
      -- Use registered WDataFifoWrite: This helps with timing and it does not introduce any risk since
      -- .. the decrement is still done immediately, the increment is delayed by one clock cycle. So worst
      -- .. case a High-Latency transfer is delayed by one cycle which is acceptable.
      v.WDataFifoWrite := WrData_Rdy_I and wr_vld_i;
      if r.AwCmdSent = '1' then
        if r.WDataFifoWrite = '1' then
          v.WrBeatsNoCmd := r.WrBeatsNoCmd - signed('0' & r.AwCmdSizeMin1); -- Decrement by size and increment by one (timing opt)
        else
          v.WrBeatsNoCmd := r.WrBeatsNoCmd - signed('0' & r.AwCmdSize);
        end if;
      elsif r.WDataFifoWrite = '1' then
        v.WrBeatsNoCmd := r.WrBeatsNoCmd + 1;
      end if;

      -- *** W Data Generation ***
      WDataTransfer_v := (r.WDataEna = '1') and (WrDataFifoOVld = '1') and (WrDataFifoORdy = '1');
      v.WDataFifoRd   := '0';
      StartWBurst_v   := false;
      case r.WFsm is
        when Idle_s =>
          if WrTransFifoOutVld = '1' then
            StartWBurst_v := true;      -- shared code
          end if;

        when NonLast_s =>
          if WDataTransfer_v then
            if r.WDataBeats = 2 then
              v.m_axi_wlast := '1';
              v.WFsm        := Last_s;
            end if;
            v.WDataBeats := r.WDataBeats - 1;
          end if;

        when Last_s =>
          if WDataTransfer_v then
            -- Immediately start next transfer
            -- .. WDataFifoRd is checked to leave time for the FIFO to complete the read in case of single cycle transfers
            if (WrTransFifoOutVld = '1') and (r.WDataFifoRd = '0') then
              StartWBurst_v := true;    -- shared code
              -- End of transfer without a next one back-to-back
            else
              v.WDataEna    := '0';
              v.WFsm        := Idle_s;
              v.m_axi_wlast := '0';
            end if;
          end if;

        when others => null;
      end case;
      -- implementation of shared code
      if StartWBurst_v then
        v.WDataFifoRd := '1';
        v.WDataEna    := '1';
        v.WDataBeats  := unsigned(WrTransFifoBeats);
        if unsigned(WrTransFifoBeats) = 1 then
          v.m_axi_wlast := '1';
          v.WFsm        := Last_s;
        else
          v.m_axi_wlast := '0';
          v.WFsm        := NonLast_s;
        end if;
      end if;

      -- *** W Response Generation ***
      v.wr_done_o  := '0';
      v.wr_error_o := '0';
      if m_axi_bvalid = '1' then
        assert WrRespFifoVld = '1' report "###ERROR###: psi_common_axi_master_simple internal error --> WrRespFifo Empty" severity error;
        v.WrOpenTrans := v.WrOpenTrans - 1; -- Use v. because it may have been modified above and this modification has not to be overriden
        if WrRespIsLast = '1' then
          if (m_axi_bresp /= Axi_Resp_Okay_c) then
            v.wr_error_o := '1';
          else
            v.wr_error_o  := r.WrRespError;
            v.wr_done_o   := not r.WrRespError;
            v.WrRespError := '0';
          end if;
        elsif m_axi_bresp /= Axi_Resp_Okay_c then
          v.WrRespError := '1';
        end if;
      end if;

    end if;

    --------------------------------------------------------------------------
    -- Read Related Code
    --------------------------------------------------------------------------
    if impl_read_g then

      -- *** Read Transfer Generation ***
      RdMax4kBeats_v := (others => '0');
      case r.ReadTfGenState is
        when Idle_s =>
          v.cmd_rd_rdy_o := '1';
          if (r.cmd_rd_rdy_o = '1') and (cmd_rd_vld_i = '1') then
            v.cmd_rd_rdy_o   := '0';
            v.RdAddr         := unsigned(AddrMasked_f(cmd_rd_addr_i));
            v.RdBeats        := unsigned(cmd_rd_size_o);
            v.RdLowLat       := cmd_rd_low_lat_i;
            v.ReadTfGenState := MaxCalc_s;
          end if;

        when MaxCalc_s =>
          RdMax4kBeats_v   := resize(unsigned('0' & not r.RdAddr(11 downto UnusedAddrBits_c)) + 1, RdMax4kBeats_v'length);
          if RdMax4kBeats_v > axi_max_beats_g then
            v.RdMaxBeats := to_unsigned(axi_max_beats_g, BeatsBits_c);
          else
            v.RdMaxBeats := RdMax4kBeats_v(BeatsBits_c - 1 downto 0);
          end if;
          v.ReadTfGenState := GenTf_s;

        when GenTf_s =>
          if (r.RdMaxBeats < r.RdBeats) then
            v.RdTfBeats  := r.RdMaxBeats;
            v.RdTfIsLast := '0';
          else
            v.RdTfBeats  := r.RdBeats(BeatsBits_c - 1 downto 0);
            v.RdTfIsLast := '1';
          end if;
          v.RdTfVld        := '1';
          v.ReadTfGenState := WriteTf_s;

        when WriteTf_s =>
          if (r.RdTfVld = '1') and (r.ArFsmRdy = '1') then
            v.RdTfVld := '0';
            v.RdBeats := r.RdBeats - r.RdTfBeats;
            v.RdAddr  := r.RdAddr + 2**UnusedAddrBits_c * r.RdTfBeats;
            if r.RdTfIsLast = '1' then
              v.ReadTfGenState := Idle_s;
            else
              v.ReadTfGenState := MaxCalc_s;
            end if;
          end if;

        when others => null;
      end case;

      -- *** AR Command Generation ***
      v.ArCmdSent     := '0';
      case r.ArFsm is
        when Idle_s =>
          if ((r.RdLowLat = '1') or (r.RdFifoSpaceFree >= signed('0' & r.RdTfBeats))) and (r.RdOpenTrans < axi_max_open_transactions_g) and (r.RdTfVld = '1') then
            v.ArFsmRdy := '1';
          end if;
          if (r.ArFsmRdy = '1') and (r.RdTfVld = '1') then
            v.ArFsmRdy      := '0';
            v.m_axi_araddr  := std_logic_vector(r.RdAddr);
            Stdlv9Bit_v     := std_logic_vector(resize(r.RdTfBeats - 1, 9));
            v.m_axi_arlen   := Stdlv9Bit_v(7 downto 0);
            v.m_axi_arvalid := '1';
            v.ArFsm         := Wait_s;
            v.ArCmdSent     := '1';
            v.ArCmdSize     := r.RdTfBeats;
            v.ArCmdSizeMin1 := r.RdTfBeats - 1;
          end if;

        when Wait_s =>
          if m_axi_arready = '1' then
            v.RdOpenTrans   := r.RdOpenTrans + 1;
            v.m_axi_arvalid := '0';
            v.ArFsm         := Idle_s;
          end if;

        when others => null;
      end case;
      -- Update counter for FIFO entries that were not yet announced in a command
      -- .. Implementation is a bit weird for timing optimization reasons.
      -- Use registered RDataFifoRead: This helps with timing and it does not introduce any risk since
      -- .. the decrement is still done immediately, the increment is delayed by one clock cycle. So worst
      -- .. case a High-Latency transfer is delayed by one cycle which is acceptable.
      v.RDataFifoRead := rd_rdy_i and RdDat_Vld_I;
      if r.ArCmdSent = '1' then
        if r.RDataFifoRead = '1' then
          v.RdFifoSpaceFree := r.RdFifoSpaceFree - signed('0' & r.ArCmdSizeMin1); -- Decrement by size and increment by one (timing opt)
        else
          v.RdFifoSpaceFree := r.RdFifoSpaceFree - signed('0' & r.ArCmdSize);
        end if;
      elsif r.RDataFifoRead = '1' then
        v.RdFifoSpaceFree := r.RdFifoSpaceFree + 1;
      end if;

      -- *** R Response Generation ***
      v.rd_done_o  := '0';
      v.rd_error_o := '0';
      if RdRespLast = '1' then
        assert RdRespFifoVld = '1' report "###ERROR###: psi_common_axi_master_simple internal error --> RdRespFifo Empty" severity error;
        v.RdOpenTrans := v.RdOpenTrans - 1; -- Use v. because it may have been modified above and this modification has not to be overriden
        if RdRespIsLast = '1' then
          if (m_axi_rresp /= Axi_Resp_Okay_c) then
            v.rd_error_o := '1';
          else
            v.rd_error_o  := r.RdRespError;
            v.rd_done_o   := not r.RdRespError;
            v.RdRespError := '0';
          end if;
        elsif m_axi_rresp /= Axi_Resp_Okay_c then
          v.RdRespError := '1';
        end if;
      end if;

    end if;

    -- *** Update Signal ***
    r_next <= v;
  end process;

  ------------------------------------------------------------------------------
  -- Registered Process
  ------------------------------------------------------------------------------
  p_reg : process(m_axi_aclk)
  begin
    if rising_edge(m_axi_aclk) then
      r <= r_next;
      if m_axi_aresetn = '0' then
        -- *** Write Related Registers ***
        if impl_write_g then
          r.cmd_wr_rdy_o    <= '0';
          r.WriteTfGenState <= Idle_s;
          r.WrTfVld         <= '0';
          r.AwFsm           <= Idle_s;
          r.AwFsmRdy        <= '0';
          r.AwCmdSent       <= '0';
          r.m_axi_awvalid   <= '0';
          r.WDataFifoRd     <= '0';
          r.WDataEna        <= '0';
          r.WrOpenTrans     <= 0;
          r.WrRespError     <= '0';
          r.wr_done_o       <= '0';
          r.wr_error_o      <= '0';
          r.WrBeatsNoCmd    <= (others => '0');
          r.WFsm            <= Idle_s;
          r.WDataFifoWrite  <= '0';
        end if;
        -- *** Read Related Registers ***
        if impl_read_g then
          r.cmd_rd_rdy_o    <= '0';
          r.ReadTfGenState  <= Idle_s;
          r.RdTfVld         <= '0';
          r.ArFsmRdy        <= '0';
          r.ArCmdSent       <= '0';
          r.m_axi_arvalid   <= '0';
          r.ArFsm           <= Idle_s;
          r.RdOpenTrans     <= (others => '0');
          r.RdRespError     <= '0';
          r.rd_done_o       <= '0';
          r.rd_error_o      <= '0';
          r.RdFifoSpaceFree <= to_signed(data_fifo_depth_g, r.RdFifoSpaceFree'length);
          r.RDataFifoRead   <= '0';
        end if;
      end if;
    end if;
  end process;

  ------------------------------------------------------------------------------
  -- Outputs
  ------------------------------------------------------------------------------
  cmd_wr_rdy_o  <= r.cmd_wr_rdy_o;
  m_axi_awaddr  <= r.m_axi_awaddr;
  m_axi_awlen   <= r.m_axi_awlen;
  m_axi_awvalid <= r.m_axi_awvalid;
  m_axi_wlast   <= r.m_axi_wlast;
  wr_done_o     <= r.wr_done_o;
  wr_error_o    <= r.wr_error_o;
  cmd_rd_rdy_o  <= r.cmd_rd_rdy_o;
  m_axi_araddr  <= r.m_axi_araddr;
  m_axi_arlen   <= r.m_axi_arlen;
  m_axi_arvalid <= r.m_axi_arvalid;
  rd_done_o     <= r.rd_done_o;
  rd_error_o    <= r.rd_error_o;

  ------------------------------------------------------------------------------
  -- Constant Outputs
  ------------------------------------------------------------------------------
  m_axi_awsize  <= std_logic_vector(to_unsigned(log2(axi_data_width_g / 8), 3));
  m_axi_arsize  <= std_logic_vector(to_unsigned(log2(axi_data_width_g / 8), 3));
  m_axi_awburst <= Axi_BurstType_Incr_c;
  m_axi_arburst <= Axi_BurstType_Incr_c;
  m_axi_awcache <= "0011";              -- According AXI reference guide
  m_axi_arcache <= "0011";              -- According AXI reference guide
  m_axi_awprot  <= "000";               -- According AXI reference guide
  m_axi_arprot  <= "000";               -- According AXI reference guide
  m_axi_awlock  <= '0';                 -- Exclusive access support not implemented
  m_axi_arlock  <= '0';                 -- Exclusive access support not implemented
  m_axi_bready  <= '1' when impl_write_g else '0';

  ------------------------------------------------------------------------------
  -- Instantiations
  ------------------------------------------------------------------------------

  -- *** Write FIFOs ***
  g_write : if impl_write_g generate

    -- FIFO for data transfer FSM
    WrTransFifoInVld <= r.AwFsmRdy and r.WrTfVld;
    i_fifo_wr_trans : entity work.psi_common_sync_fifo
      generic map(
        rst_pol_g      => '0',
        width_g        => BeatsBits_c,
        depth_g        => axi_max_open_transactions_g,
        alm_full_on_g  => false,
        alm_empty_on_g => false,
        ram_style_g    => "auto",
        ram_behavior_g => ram_behavior_g)
      port map(
        clk_i => m_axi_aclk,
        rst_i => m_axi_aresetn,
        dat_i => std_logic_vector(r.WrTfBeats),
        vld_i => WrTransFifoInVld,
        rdy_o => open,                  -- Not required since maximum of open transactions is limitted
        dat_o => WrTransFifoBeats,
        vld_o => WrTransFifoOutVld,
        rdy_i => r.WDataFifoRd);

    -- Write Data FIFO
    b_fifo_wr_data : block
      signal InData  : std_logic_vector(wr_dat_i'length + wr_data_be_i'length - 1 downto 0);
      signal OutData : std_logic_vector(InData'range);
    begin
      InData(wr_dat_i'high downto wr_dat_i'low)                          <= wr_dat_i;
      InData(wr_dat_i'high + wr_data_be_i'length downto wr_dat_i'high + 1) <= wr_data_be_i;
      i_fifo_wr_data : entity work.psi_common_sync_fifo
        generic map(
          width_g        => wr_dat_i'length + wr_data_be_i'length,
          depth_g        => data_fifo_depth_g,
          alm_full_on_g  => false,
          alm_empty_on_g => false,
          ram_style_g    => "auto",
          ram_behavior_g => ram_behavior_g,
          rst_pol_g      => '0')
        port map(
          clk_i => m_axi_aclk,
          rst_i => m_axi_aresetn,
          dat_i => InData,
          vld_i => wr_vld_i,
          rdy_o => WrData_Rdy_I,
          dat_o => OutData,
          vld_o => WrDataFifoOVld,
          rdy_i => WrDataFifoORdy
        );
      m_axi_wdata                                                        <= OutData(wr_dat_i'high downto wr_dat_i'low);
      m_axi_wstrb                                                        <= OutData(wr_dat_i'high + wr_data_be_i'length downto wr_dat_i'high + 1);

      m_axi_wvalid   <= WrDataFifoOVld and r.WDataEna;
      WrDataFifoORdy <= m_axi_wready and r.WDataEna;

      wr_rdy_o <= WrData_Rdy_I;
    end block;

    -- FIFO for write response FSM
    i_fifo_wr_resp : entity work.psi_common_sync_fifo
      generic map(
        width_g        => 1,
        depth_g        => axi_max_open_transactions_g,
        alm_full_on_g  => false,
        alm_empty_on_g => false,
        ram_style_g    => "auto",
        ram_behavior_g => ram_behavior_g,
        rst_pol_g      => '0')
      port map(
        clk_i    => m_axi_aclk,
        rst_i    => m_axi_aresetn,
        dat_i(0) => r.WrTfIsLast,
        vld_i    => WrTransFifoInVld,
        rdy_o    => open,               -- Not required since maximum of open transactions is limitted
        dat_o(0) => WrRespIsLast,
        vld_o    => WrRespFifoVld,
        rdy_i    => m_axi_bvalid);
  end generate;

  -- Tie signals to ground if read not implemented
  g_nwrite : if not impl_write_g generate
    m_axi_wstrb  <= (others => '0');
    m_axi_wdata  <= (others => '0');
    m_axi_wvalid <= '0';
    wr_rdy_o     <= '0';
  end generate;

  -- *** Read FIFOs ***
  g_read : if impl_read_g generate

    -- Read Data FIFO
    b_fifo_rd_data : block
    begin
      i_fifo_wr_data : entity work.psi_common_sync_fifo
        generic map(
          width_g        => rd_dat_o'length,
          depth_g        => data_fifo_depth_g,
          alm_full_on_g  => false,
          alm_empty_on_g => false,
          ram_style_g    => "auto",
          ram_behavior_g => ram_behavior_g,
          rst_pol_g      => '0'
        )
        port map(
          clk_i => m_axi_aclk,
          rst_i => m_axi_aresetn,
          dat_i => m_axi_rdata,
          vld_i => m_axi_rvalid,
          rdy_o => M_Axi_RReady_I,
          dat_o => rd_dat_o,
          vld_o => RdDat_Vld_I,
          rdy_i => rd_rdy_i
        );

      rd_vld_o     <= RdDat_Vld_I;
      m_axi_rready <= M_Axi_RReady_I;
    end block;

    -- FIFO for read response FSM
    RdTransFifoInVld <= r.ArFsmRdy and r.RdTfVld;
    RdRespLast       <= m_axi_rvalid and M_Axi_RReady_I and m_axi_rlast;
    i_fifo_rd_resp : entity work.psi_common_sync_fifo
      generic map(
        width_g        => 1,
        depth_g        => axi_max_open_transactions_g,
        alm_full_on_g  => false,
        alm_empty_on_g => false,
        ram_style_g    => "auto",
        ram_behavior_g => ram_behavior_g,
        rst_pol_g      => '0'
      )
      port map(
        clk_i    => m_axi_aclk,
        rst_i    => m_axi_aresetn,
        dat_i(0) => r.RdTfIsLast,
        vld_i    => RdTransFifoInVld,
        rdy_o    => open,               -- Not required since maximum of open transactions is limitted
        dat_o(0) => RdRespIsLast,
        vld_o    => RdRespFifoVld,
        rdy_i    => RdRespLast
      );

  end generate;

  -- Tie signals to ground if read not implemented
  g_nread : if not impl_read_g generate
    m_axi_rready <= '0';
    rd_dat_o     <= (others => '0');
    rd_vld_o     <= '0';
  end generate;

end architecture;

