174	
175	  procedure ApplyCommand(Addr               : in integer;
176	                         Size               : in integer;
177	                         LowLat             : in boolean;
178	                         signal CmdX_Addr   : out std_logic_vector(axi_addr_width_g-1 downto 0);
179	                         signal CmdX_Size   : out std_logic_vector(user_transaction_size_bits_g-1 downto 0);
180	                         signal CmdX_LowLat : out std_logic;
181	                         signal CmdX_Vld    : out std_logic;
182	                         signal CmdX_Rdy    : in std_logic;
183	                         signal Clk         : in std_logic) is
184	  begin
185	    wait until rising_edge(Clk);
186	    CmdX_Addr <= std_logic_vector(to_unsigned(Addr, CmdX_Addr'length));
187	    CmdX_Size <= std_logic_vector(to_unsigned(Size, CmdX_Size'length));
188	    if LowLat then
189	      CmdX_LowLat <= '1';
190	    else
191	      CmdX_LowLat <= '0';
192	    end if;
193	    CmdX_Vld  <= '1';
194	    wait until rising_edge(Clk) and CmdX_Rdy = '1';
195	    CmdX_Vld  <= '0';
196	  end procedure;
197	
198	  procedure ApplyWrDataSingle(Data              : in integer;
199	                              Be                : in std_logic_vector;
200	                              signal wr_dat_i : out std_logic_vector(axi_data_width_g-1 downto 0);
201	                              signal wr_data_be   : out std_logic_vector;
202	                              signal wr_vld_i  : out std_logic;
203	                              signal wr_rdy_o  : in std_logic;
204	                              signal Clk        : in std_logic) is
205	  begin
206	    wr_data_be   <= Be;
207	    wr_dat_i <= std_logic_vector(to_unsigned(Data, wr_dat_i'length));
208	    wr_vld_i  <= '1';
209	    wait until rising_edge(Clk) and wr_rdy_o = '1';
210	    wr_vld_i  <= '0';
211	  end procedure;
212	
213	  procedure ApplyWrDataMulti(Start             : in integer;
214	                             Incr              : in integer;
215	                             Size              : in integer;
216	                             FirstBe           : in std_logic_vector;
217	                             LastBe            : in std_logic_vector;
218	                             signal wr_dat_i : out std_logic_vector(axi_data_width_g-1 downto 0);
219	                             signal wr_data_be   : out std_logic_vector;
220	                             signal wr_vld_i  : out std_logic;
221	                             signal wr_rdy_o  : in std_logic;
222	                             signal Clk        : in std_logic;
223	                             VldLowCyc         : in integer := 0) is
224	    variable DataCnt_v : integer                          := Start;
225	    constant LastIdx_c : integer                          := Size - 1;
226	    constant BeOnes_c  : std_logic_vector(wr_data_be'range) := (others => '1');
227	  begin
228	    for i in 0 to Size - 1 loop
229	      if i = 0 then
230	        wr_data_be <= FirstBe;
231	      elsif i = LastIdx_c then
232	        wr_data_be <= LastBe;
233	      else
234	        wr_data_be <= BeOnes_c;
235	      end if;
236	      wr_dat_i <= std_logic_vector(to_unsigned(DataCnt_v, wr_dat_i'length));
237	      wr_vld_i  <= '1';
238	      wait until rising_edge(Clk) and wr_rdy_o = '1';
239	      DataCnt_v  := (DataCnt_v + Incr) mod 2**axi_data_width_g;
240	      if VldLowCyc > 0 then
241	        wr_vld_i <= '0';
242	        for i in 0 to VldLowCyc - 1 loop
243	          wait until rising_edge(Clk);
244	        end loop;
245	      end if;
246	    end loop;
247	    wr_vld_i <= '0';
248	  end procedure;
249	
250	  procedure CheckRdDataSingle(Data              : in integer;
251	                              signal rd_dat_o : in std_logic_vector(axi_data_width_g-1 downto 0);
252	                              signal rd_vld_o  : in std_logic;
253	                              signal rd_rdy_i  : out std_logic;
254	                              signal Clk        : in std_logic) is
255	  begin
256	    rd_rdy_i <= '1';
257	    wait until rising_edge(Clk) and rd_vld_o = '1';
258	    StdlvCompareInt(Data, rd_dat_o, "Received wrong Read Data", false);
259	    rd_rdy_i <= '0';
260	  end procedure;
261	
262	  procedure CheckRdDataMulti(Start             : in integer;
263	                             Incr              : in integer;
264	                             Size              : in integer;
265	                             signal rd_dat_o : in std_logic_vector(axi_data_width_g-1 downto 0);
266	                             signal rd_vld_o  : in std_logic;
267	                             signal rd_rdy_i  : out std_logic;
268	                             signal Clk        : in std_logic;
269	                             RdyLowCyc         : in integer := 0) is
270	    variable DataCnt_v : integer := Start;
271	    constant LastIdx_c : integer := Size - 1;
272	  begin
273	    for i in 0 to Size - 1 loop
274	      rd_rdy_i <= '1';
275	      wait until rising_edge(Clk) and rd_vld_o = '1';
276	      StdlvCompareInt(DataCnt_v, rd_dat_o, "Received wrong Read Data in Burst", false);
277	      DataCnt_v := (DataCnt_v + Incr) mod 2**axi_data_width_g;
278	      if RdyLowCyc > 0 then
279	        rd_rdy_i <= '0';
280	        for i in 0 to RdyLowCyc - 1 loop
281	          wait until rising_edge(Clk);
282	        end loop;
283	      end if;
284	    end loop;
285	    rd_rdy_i <= '0';
286	  end procedure;
287	
288	  procedure WaitForCompletion(Success        : in boolean;
289	                              WaitTime       : in time;
290	                              signal X_Done  : in std_logic;
291	                              signal X_Error : in std_logic;
292	                              signal Clk     : in std_logic) is
293	  begin
294	    if Success then
295	      wait until rising_edge(Clk) and X_Done = '1' for WaitTime;
296	      StdlCompare(1, X_Done, "No Done");
297	    else
298	      wait until rising_edge(Clk) and X_Error = '1' for WaitTime;
299	      StdlCompare(1, X_Error, "No Error");
300	    end if;
301	  end procedure;
302	
303	  procedure AxiCheckWrSingle(Addr          : in integer;
304	                             Data          : in integer;
305	                             Be            : in std_logic_vector;
306	                             Resp          : in std_logic_vector;
307	                             signal axi_ms : in axi_ms_t;
308	                             signal axi_sm : out axi_sm_t;
309	                             signal Clk    : in std_logic;
310	                             SendResp      : in boolean := true) is
311	  begin
312	    axi_expect_aw(Addr, AxSIZE_2_c, 1 - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
313	    axi_expect_wd_single(std_logic_vector(to_unsigned(Data, axi_data_width_g)), Be, axi_ms, axi_sm, Clk);
314	    if SendResp then
315	      axi_apply_bresp(Resp, axi_ms, axi_sm, Clk);
316	    end if;
317	  end procedure;
318	
319	  procedure AxiCheckWrBurst(Addr          : in integer;
320	                            Start         : in integer;
321	                            Incr          : in integer;
322	                            Size          : in integer;
323	                            FirstBe       : in std_logic_vector;
324	                            LastBe        : in std_logic_vector;
325	                            Resp          : in std_logic_vector;
326	                            signal axi_ms : in axi_ms_t;
327	                            signal axi_sm : out axi_sm_t;
328	                            signal Clk    : in std_logic;
329	                            SendResp      : in boolean := true;
330	                            AwRdyDelay    : in time    := 0 ns;
331	                            WRdyLowCyc    : in integer := 0) is
332	  begin
333	    if AwRdyDelay > 0 ns then
334	      wait for AwRdyDelay;
335	      wait until rising_edge(Clk);
336	    end if;
337	    axi_expect_aw(Addr, AxSIZE_2_c, Size - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
338	    axi_expect_wd_burst(Size, Start, Incr, FirstBe, LastBe, axi_ms, axi_sm, Clk, WRdyLowCyc);
339	    if SendResp then
340	      axi_apply_bresp(Resp, axi_ms, axi_sm, Clk);
341	    end if;
342	  end procedure;
343	
344	  procedure AxiCheckRdSingle(Addr          : in integer;
345	                             Data          : in integer;
346	                             Resp          : in std_logic_vector;
347	                             signal axi_ms : in axi_ms_t;
348	                             signal axi_sm : out axi_sm_t;
349	                             signal Clk    : in std_logic) is
350	  begin
351	    axi_expect_ar(Addr, AxSIZE_2_c, 1 - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
352	    axi_apply_rresp_single(std_logic_vector(to_unsigned(Data, axi_data_width_g)), Resp, axi_ms, axi_sm, Clk);
353	  end procedure;
354	
355	  procedure AxiCheckRdBurst(Addr          : in integer;
356	                            Start         : in integer;
357	                            Incr          : in integer;
358	                            Size          : in integer;
359	                            Resp          : in std_logic_vector;
360	                            signal axi_ms : in axi_ms_t;
361	                            signal axi_sm : out axi_sm_t;
362	                            signal Clk    : in std_logic;
363	                            ArRdyDelay    : in time    := 0 ns;
364	                            RVldLowCyc    : in integer := 0) is
365	  begin
366	    if ArRdyDelay > 0 ns then
367	      wait for ArRdyDelay;
368	      wait until rising_edge(Clk);
369	    end if;
370	    axi_expect_ar(Addr, AxSIZE_2_c, Size - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
371	    axi_apply_rresp_burst(Size, Start, Incr, Resp, axi_ms, axi_sm, Clk, RVldLowCyc);
372	  end procedure;
373	
374	  procedure DbgPrint(Enable : in boolean;
375	                     Str    : in string) is
376	  begin
377	    if Enable then
378	      Print(Str);
379	    end if;
380	  end procedure;
381	
382	end;
383

