287	
288	      -- *** Single word wirte [low latency, command before data] ***
289	      WaitCase(5, Clk);
290	      wait for 200 ns;
291	      wait until rising_edge(Clk);
292	      ApplyWrDataSingle(16#BABE#, "11", wr_dat_i, wr_data_be, wr_vld_i, wr_rdy_o, Clk);
293	
294	      -- *** Single word wirte [low latency, command after data + error] ***
295	      WaitCase(6, Clk);
