297	      ApplyWrDataSingle(16#0001#, "11", wr_dat_i, wr_data_be, wr_vld_i, wr_rdy_o, Clk);
298	
299	      -- *** Burst wirte[low latency] ***
300	      WaitCase(7, Clk);
301	      wait until rising_edge(Clk);
302	      ApplyWrDataMulti(16#1000#, 1, 12, "10", "01", wr_dat_i, wr_data_be, wr_vld_i, wr_rdy_o, Clk);
303	    end if;
