478	    if Generics_c.impl_write_g then
479	      -- *** Single word wirte [high latency, command+data together] ***
480	      WaitCase(0, Clk);
481	      AxiCheckWrSingle(16#12345678#, 16#BEEF#, "10", xRESP_OKAY_c, axi_ms, axi_sm, Clk);
482	
483	      -- *** Single word wirte [high latency, command before data] ***
484	      WaitCase(1, Clk);
485	      while not ExpectCmd_v loop
486	        wait until rising_edge(Clk);
487	        assert axi_ms.awvalid = '0' report "###ERROR###: High Latency did not wait for data in fifo" severity error;
488	      end loop;
489	      AxiCheckWrSingle(16#00010020#, 16#BABE#, "11", xRESP_OKAY_c, axi_ms, axi_sm, Clk);
490	
491	      -- *** Single word wirte [high latency, command before data] ***
492	      WaitCase(2, Clk);
493	      AxiCheckWrSingle(16#00010030#, 16#0001#, "11", xRESP_DECERR_c, axi_ms, axi_sm, Clk);
494	
495	      -- *** Burst wirte[high latency] ***
496	      WaitCase(3, Clk);
497	      while not ExpectCmd_v loop
498	        wait until rising_edge(Clk);
499	        assert axi_ms.awvalid = '0' report "###ERROR###: High Latency did not wait for data in fifo" severity error;
500	      end loop;
501	      AxiCheckWrBurst(16#00020000#, 16#1000#, 1, 12, "10", "01", xRESP_OKAY_c, axi_ms, axi_sm, Clk);
502	    end if;
503	
504	    ------------------------------------------------------------------
505	    -- Low Latency Writes
506	    ------------------------------------------------------------------	
507	    if Generics_c.impl_write_g then
508	      -- *** Single word wirte [low latency, command+data together] ***
509	      WaitCase(4, Clk);
510	      AxiCheckWrSingle(16#12345678#, 16#BEEF#, "10", xRESP_OKAY_c, axi_ms, axi_sm, Clk);
511	
512	      -- *** Single word wirte [low latency, command before data] ***
513	      WaitCase(5, Clk);
514	      AxiCheckWrSingle(16#00010020#, 16#BABE#, "11", xRESP_OKAY_c, axi_ms, axi_sm, Clk);
515	
516	      -- *** Single word wirte [low latency, command before data] ***
517	      WaitCase(6, Clk);
