519	
520	      -- *** Burst wirte[low latency] ***
521	      WaitCase(7, Clk);
522	      AxiCheckWrBurst(16#00020000#, 16#1000#, 1, 12, "10", "01", xRESP_OKAY_c, axi_ms, axi_sm, Clk);
523	    end if;
524	
525	    ------------------------------------------------------------------
526	    -- High Latency Reads
527	    ------------------------------------------------------------------
528	    if Generics_c.impl_read_g then
529	      -- *** Single word read [high latency, space available] ***	
530	      WaitCase(8, Clk);
531	      AxiCheckRdSingle(16#12345678#, 16#BEEF#, xRESP_OKAY_c, axi_ms, axi_sm, Clk);
532	
533	      -- *** Burst read [high latency, space available] ***
534	      WaitCase(9, Clk);
535	      AxiCheckRdBurst(16#00020000#, 16#1000#, 1, 12, xRESP_DECERR_c, axi_ms, axi_sm, Clk);
536	
537	      -- *** Single word read [high latency, wait for space] ***
538	      WaitCase(10, Clk);
539	      -- Read to fill the FIFO
540	      axi_expect_ar(16#00020000#, AxSIZE_2_c, data_fifo_depth_g - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
541	      -- Delay the response and check if the read command is delayed
542	      CheckNoActivity(axi_ms.arvalid, 0.2 us, 0, "Unexpected read command received");
543	      wait until rising_edge(Clk);
544	      -- send response
545	      axi_apply_rresp_burst(data_fifo_depth_g, 16#1000#, 1, xRESP_OKAY_c, axi_ms, axi_sm, Clk);
546	      -- Test Read (can happen now)
547	      AxiCheckRdSingle(16#12345678#, 16#BEEF#, xRESP_OKAY_c, axi_ms, axi_sm, Clk);
548	
549	      -- *** Burst read [high latency, wait for space] ***
550	      WaitCase(11, Clk);
551	      -- Read to fill the FIFO
552	      axi_expect_ar(16#00020000#, AxSIZE_2_c, data_fifo_depth_g - 4 - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
553	      -- Delay the response and check if the read command is delayed
554	      CheckNoActivity(axi_ms.arvalid, 0.2 us, 0, "Unexpected read command received");
555	      wait until rising_edge(Clk);
556	      -- send response
557	      axi_apply_rresp_burst(data_fifo_depth_g - 4, 16#1000#, 1, xRESP_OKAY_c, axi_ms, axi_sm, Clk);
558	      -- Test Read (can happen now)
559	      AxiCheckRdBurst(16#00021000#, 16#2000#, 1, data_fifo_depth_g - 4, xRESP_OKAY_c, axi_ms, axi_sm, Clk);
560	    end if;
561	
562	    ------------------------------------------------------------------
563	    -- Low Latency Reads
564	    ------------------------------------------------------------------
565	    if Generics_c.impl_read_g then
566	      -- *** Single word read [low latency, space available] ***	
567	      WaitCase(12, Clk);
568	      AxiCheckRdSingle(16#12345678#, 16#BEEF#, xRESP_OKAY_c, axi_ms, axi_sm, Clk);
569	
570	      -- *** Burst read [low latency, space available] ***
