572	      AxiCheckRdBurst(16#00020000#, 16#1000#, 1, 12, xRESP_DECERR_c, axi_ms, axi_sm, Clk);
573	
574	      -- *** Single word read [low latency, no space] ***
575	      WaitCase(14, Clk);
