577	      axi_expect_ar(16#00020000#, AxSIZE_2_c, data_fifo_depth_g - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
578	      axi_expect_ar(16#12345678#, AxSIZE_2_c, 1 - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
