581	      axi_apply_rresp_single(X"BEEF", xRESP_OKAY_c, axi_ms, axi_sm, Clk);
582	
583	      -- *** Burst read [low latency, no space] ***	
584	      WaitCase(15, Clk);
585	      -- Expect commands
586	      axi_expect_ar(16#00020000#, AxSIZE_2_c, data_fifo_depth_g - 4 - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
587	      axi_expect_ar(16#00021000#, AxSIZE_2_c, data_fifo_depth_g - 4 - 1, xBURST_INCR_c, axi_ms, axi_sm, Clk);
588	      -- Send responses
